// useScrollToTop.js
import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

const useScrollToTop = () => {
  const { pathname } = useLocation();

  useEffect(() => {
    window.scrollTo(0, 0);
    setTimeout(() => {
        window.scrollTo(0, 0);
      }, 1000);
  }, [pathname]); 

  useEffect(() => { 
    window.scrollTo(0, 0);
    setTimeout(() => {
      window.scrollTo(0, 0);
    }, 1000);
  }, [])
};

export default useScrollToTop;
